def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        acc = 0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(1, a + 5):
                    val = ((ratio - a) ** 6) / (a * b * 1.1 + 2)
                    acc += val * np.sin(ratio * b / (a + 2))
            acc += (np.exp(ratio - 8) * np.cos(ratio * 1.3)) ** 2
        elif 5 < ratio <= 8:
            for p in range(2, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 4):
                    term = ((ratio - p) ** 4) * np.cos(ratio * p / 1.3) / (q + 1)
                    acc += np.tanh(term) * 1.5
            acc += np.log(ratio) * 12 - np.tanh(ratio - 5) * 3.5
        elif 3 <= ratio <= 5:
            s = 0
            for r in range(1, 18):
                s += ((ratio - 3) ** r) / (r * 2.2) * np.sin(r * ratio * 0.8)
            acc = (s * np.sin(8 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (5 - ratio)) * 2
        elif 1 < ratio < 3:
            s = 0
            for n in range(1, 14):
                s += ((3 - ratio) ** n) / (n ** 2 + 1)
            if cap < item * 1.3:
                penalty = np.sqrt(item / (cap + 1)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            acc = s + penalty + np.exp(-2 / (ratio + 0.03))
            for m in range(1, 7):
                acc += np.sin(m * ratio * i) * ((ratio - 1) ** m) / m
        elif 0.6 <= ratio < 1:
            s = 0
            for n in range(1, 18):
                s += ((1 - ratio) ** n) / (n * 3)
            acc = s
            if (i + int(item * 2)) % 5 == 0:
                acc *= np.log1p(cap + 5) * 1.7
            else:
                acc /= (np.sqrt(cap + 2) + 3)
            for j in range(1, 8):
                acc += ((1 - ratio) ** j) * np.cos(j * item * 1.5) * 0.8
        elif 0.2 <= ratio < 0.6:
            s = 0
            for k in range(1, 20):
                s += ((0.6 - ratio) ** k) / (k * 4) * np.sin(k * ratio * 3)
            acc = s + 1 / (cap + 5)
            if int(item * 1.8) % 6 == 0:
                acc *= 3.2
            else:
                acc /= 3.2
            if cap < item * 0.3:
                acc += np.log1p(item * cap) * 5
            else:
                acc -= np.exp(-ratio * 2.2) * 5
            for m in range(1, 10):
                acc += ((0.6 - ratio) ** m) / (m * 8) * np.sin(item * m * 1.4)
        else:
            s = 0
            for t in range(1, 14):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.cos(t * item * 1.1)
            acc = s + 3 / (cap + 6)
            if int(item * 0.9) % 7 == 0:
                acc *= 4
            else:
                acc /= 4
            if cap < item * 0.2:
                acc += np.log1p(item * cap) * 6
            else:
                acc -= np.exp(-ratio * 3) * 6
            for u in range(1, 10):
                acc += ((0.2 - ratio) ** u) / (u * 9) * np.sin(item * u * 1.0)
        if cap < item * 0.5:
            acc += np.log1p(item ** 3 * cap) * 6
        elif cap > item * 3.0:
            acc -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                acc += np.sin(ratio * (i + idx) * 1.3) * 0.5
            else:
                acc -= np.cos(ratio * (i + idx) * 1.2) * 0.5
        if i % 4 == 0:
            acc += np.sin(ratio * i * 1.4) * 0.8
        else:
            acc -= np.cos(ratio * i * 1.4) * 0.8
        if i % 2 == 0:
            for z in range(1, 4):
                acc += np.tanh(np.sin(ratio * z * i)) * (z / 2)
        else:
            for z in range(4, 7):
                acc -= np.tanh(np.cos(ratio * z * i)) * (z / 3)
        if (i + int(item)) % 7 == 0:
            acc *= 1.4
        else:
            acc /= 1.4
        priorities[i] = acc
    return priorities
